public static long solve(String s) {
    int n = s.length();
    long[] l_before = new long[n + 1];
    for (int i = 0; i < n; i++) {
        l_before[i + 1] = l_before[i] + (s.charAt(i) == 'L' ? 1 : 0);
    }

    long[] t_after = new long[n + 1];
    for (int i = n - 1; i >= 0; i--) {
        t_after[i] = t_after[i + 1] + (s.charAt(i) == 'T' ? 1 : 0);
    }

    long original = 0;
    for (int i = 0; i < n; i++) {
        if (s.charAt(i) == 'C') {
            original += l_before[i] * t_after[i + 1];
        }
    }

    long sum_t_after_c = 0;
    for (int i = 0; i < n; i++) {
        if (s.charAt(i) == 'C') {
            sum_t_after_c += t_after[i + 1];
        }
    }

    long sum_l_before_c = 0;
    for (int i = 0; i < n; i++) {
        if (s.charAt(i) == 'C') {
            sum_l_before_c += l_before[i];
        }
    }

    long max_l_before_t_after = 0;
    for (int i = 0; i <= n; i++) {
        long current = l_before[i] * t_after[i];
        if (current > max_l_before_t_after) {
            max_l_before_t_after = current;
        }
    }

    long max_increase = Math.max(0, Math.max(sum_t_after_c, Math.max(sum_l_before_c, max_l_before_t_after)));
    return original + max_increase;
}
